sql:
SELECT name
FROM breeds
WHERE popularity = (SELECT MAX(popularity) FROM breeds);

SELECT name, COUNT(*) AS bloom_count
FROM breeds
GROUP BY name;

SELECT name, popularity
FROM breeds
ORDER BY popularity DESC;

external_knowledge:
- Popularity score greater than 10 indicates a popular breed;
- Average rating reflects user satisfaction;
- Grooming frequency and coat length are important factors for potential dog owners.

sql:
SELECT name, popularity, description
FROM breeds
WHERE breed_id = 1;
